import type { ComponentProps, ComponentRef, RefObject } from 'react';
import { Dialog as DialogPrimitive, useDialog, useDialogContext } from '@ark-ui/react/dialog';
import { clsx } from 'clsx';
import { forwardRef, useEffect } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import { CloseButton } from '../close-button';
import styles from './Lightbox.module.css';

const DEFAULT_CLOSE_LABEL = 'Close image';

type LightboxImageSelectDetails = {
  alt?: string;
  element: HTMLImageElement;
  src: string;
};

type LightboxImageProps = ComponentProps<'img'> & {
  closeOnClick?: boolean;
};

type LightboxBindProps = {
  onImageSelect: (details: LightboxImageSelectDetails) => void;
  selector?: string;
  rootRef?: RefObject<HTMLElement | null>;
  rootSelector?: string;
};

const preloadedImageSources = new Set<string>();

function preloadImage(src?: string) {
  if (!src || typeof Image === 'undefined' || preloadedImageSources.has(src)) {
    return;
  }

  preloadedImageSources.add(src);
  const image = new Image();
  image.src = src;
}

function resolveImage(
  target: EventTarget | null,
  selector: string,
  rootNode: HTMLElement,
): LightboxImageSelectDetails | null {
  if (!(target instanceof Element)) {
    return null;
  }

  const matchedNode = target.closest(selector);
  if (!matchedNode || !rootNode.contains(matchedNode)) {
    return null;
  }

  const imageNode =
    matchedNode instanceof HTMLImageElement ? matchedNode : matchedNode.querySelector('img');
  if (!(imageNode instanceof HTMLImageElement) || !rootNode.contains(imageNode)) {
    return null;
  }

  const source = imageNode.dataset.lightboxSrc ?? imageNode.currentSrc ?? imageNode.src;
  if (!source) {
    return null;
  }

  return {
    src: source,
    alt: imageNode.alt || undefined,
    element: imageNode,
  };
}

function LightboxRoot(props: ComponentProps<typeof DialogPrimitive.Root>) {
  return <DialogPrimitive.Root {...props} />;
}

function LightboxRootProvider(props: ComponentProps<typeof DialogPrimitive.RootProvider>) {
  return <DialogPrimitive.RootProvider {...props} />;
}

const LightboxTrigger = forwardRef<
  ComponentRef<typeof DialogPrimitive.Trigger>,
  ComponentProps<typeof DialogPrimitive.Trigger>
>(function LightboxTrigger({ className, ...props }, ref) {
  return (
    <DialogPrimitive.Trigger
      ref={ref}
      data-slot="lightbox-trigger"
      className={clsx(styles.trigger, normalizeClassName(className))}
      {...props}
    />
  );
});

const LightboxBackdrop = forwardRef<
  ComponentRef<typeof DialogPrimitive.Backdrop>,
  ComponentProps<typeof DialogPrimitive.Backdrop>
>(function LightboxBackdrop({ className, ...props }, ref) {
  return (
    <DialogPrimitive.Backdrop
      ref={ref}
      data-slot="lightbox-backdrop"
      className={clsx(styles.backdrop, normalizeClassName(className))}
      {...props}
    />
  );
});

const LightboxPositioner = forwardRef<
  ComponentRef<typeof DialogPrimitive.Positioner>,
  ComponentProps<typeof DialogPrimitive.Positioner>
>(function LightboxPositioner({ className, ...props }, ref) {
  return (
    <DialogPrimitive.Positioner
      ref={ref}
      data-slot="lightbox-positioner"
      className={clsx(styles.positioner, normalizeClassName(className))}
      {...props}
    />
  );
});

const LightboxContent = forwardRef<
  ComponentRef<typeof DialogPrimitive.Content>,
  ComponentProps<typeof DialogPrimitive.Content>
>(function LightboxContent({ className, ...props }, ref) {
  return (
    <DialogPrimitive.Content
      ref={ref}
      data-slot="lightbox-content"
      className={clsx(styles.content, normalizeClassName(className))}
      {...props}
    />
  );
});

const LightboxTitle = forwardRef<
  ComponentRef<typeof DialogPrimitive.Title>,
  ComponentProps<typeof DialogPrimitive.Title>
>(function LightboxTitle({ className, ...props }, ref) {
  return (
    <DialogPrimitive.Title
      ref={ref}
      data-slot="lightbox-title"
      className={normalizeClassName(className)}
      {...props}
    />
  );
});

const LightboxDescription = forwardRef<
  ComponentRef<typeof DialogPrimitive.Description>,
  ComponentProps<typeof DialogPrimitive.Description>
>(function LightboxDescription({ className, ...props }, ref) {
  return (
    <DialogPrimitive.Description
      ref={ref}
      data-slot="lightbox-description"
      className={normalizeClassName(className)}
      {...props}
    />
  );
});

const LightboxCloseTrigger = forwardRef<
  ComponentRef<typeof DialogPrimitive.CloseTrigger>,
  ComponentProps<typeof DialogPrimitive.CloseTrigger>
>(function LightboxCloseTrigger({ className, ...props }, ref) {
  return (
    <DialogPrimitive.CloseTrigger
      ref={ref}
      data-slot="lightbox-close-trigger"
      className={normalizeClassName(className)}
      {...props}
    />
  );
});

const LightboxCloseIcon = forwardRef<
  ComponentRef<typeof CloseButton.Root>,
  Omit<ComponentProps<typeof DialogPrimitive.CloseTrigger>, 'asChild'>
>(function LightboxCloseIcon(
  { className, children, 'aria-label': ariaLabel = DEFAULT_CLOSE_LABEL, ...props },
  ref,
) {
  const dialog = useDialogContext();

  return (
    <DialogPrimitive.CloseTrigger asChild {...props}>
      <CloseButton.Root
        ref={ref}
        data-slot="lightbox-close-icon"
        data-state={dialog.open ? 'open' : 'closed'}
        aria-label={ariaLabel}
        className={clsx(styles.closeIcon, normalizeClassName(className))}
      >
        {children}
      </CloseButton.Root>
    </DialogPrimitive.CloseTrigger>
  );
});

const LightboxImage = forwardRef<HTMLImageElement, LightboxImageProps>(function LightboxImage(
  { className, closeOnClick = false, onClick, ...props },
  ref,
) {
  const dialog = useDialogContext();

  const handleClick: ComponentProps<'img'>['onClick'] = (event) => {
    onClick?.(event);

    if (closeOnClick && !event.defaultPrevented) {
      dialog.setOpen(false);
    }
  };

  return (
    <img
      ref={ref}
      data-slot="lightbox-image"
      data-close-on-click={closeOnClick ? '' : undefined}
      className={clsx(styles.image, normalizeClassName(className))}
      onClick={handleClick}
      {...props}
    />
  );
});

const LightboxGallery = forwardRef<HTMLDivElement, ComponentProps<'div'>>(function LightboxGallery(
  { className, ...props },
  ref,
) {
  return (
    <div
      ref={ref}
      data-slot="lightbox-gallery"
      className={clsx(styles.gallery, normalizeClassName(className))}
      {...props}
    />
  );
});

function LightboxBind({
  onImageSelect,
  selector = 'img',
  rootRef,
  rootSelector,
}: LightboxBindProps) {
  const { setOpen } = useDialogContext();

  useEffect(() => {
    const rootNode =
      rootRef?.current ?? (rootSelector ? document.querySelector<HTMLElement>(rootSelector) : null);
    if (!rootNode) {
      return;
    }

    const handleClick = (event: MouseEvent) => {
      const nextImage = resolveImage(event.target, selector, rootNode);
      if (!nextImage) {
        return;
      }

      onImageSelect(nextImage);
      setOpen(true);
    };

    const handlePreload = (target: EventTarget | null) => {
      const nextImage = resolveImage(target, selector, rootNode);
      if (!nextImage) {
        return;
      }

      preloadImage(nextImage.src);
    };

    const handlePointerEnter = (event: PointerEvent) => {
      handlePreload(event.target);
    };

    const handleFocusIn = (event: FocusEvent) => {
      handlePreload(event.target);
    };

    rootNode.addEventListener('click', handleClick);
    rootNode.addEventListener('pointerenter', handlePointerEnter, true);
    rootNode.addEventListener('focusin', handleFocusIn);

    return () => {
      rootNode.removeEventListener('click', handleClick);
      rootNode.removeEventListener('pointerenter', handlePointerEnter, true);
      rootNode.removeEventListener('focusin', handleFocusIn);
    };
  }, [onImageSelect, rootRef, rootSelector, selector, setOpen]);

  return null;
}

const LightboxContext = DialogPrimitive.Context;

const Lightbox = Object.assign(LightboxRoot, {
  Root: LightboxRoot,
  RootProvider: LightboxRootProvider,
  Trigger: LightboxTrigger,
  Backdrop: LightboxBackdrop,
  Positioner: LightboxPositioner,
  Content: LightboxContent,
  Title: LightboxTitle,
  Description: LightboxDescription,
  CloseTrigger: LightboxCloseTrigger,
  CloseIcon: LightboxCloseIcon,
  Image: LightboxImage,
  Gallery: LightboxGallery,
  Bind: LightboxBind,
  Context: LightboxContext,
});

export {
  Lightbox,
  LightboxBind,
  LightboxGallery,
  LightboxImage,
  useDialog as useLightbox,
  useDialogContext as useLightboxContext,
};
export type { LightboxBindProps, LightboxImageSelectDetails };
export type {
  DialogFocusOutsideEvent as LightboxFocusOutsideEvent,
  DialogInteractOutsideEvent as LightboxInteractOutsideEvent,
  DialogOpenChangeDetails as LightboxOpenChangeDetails,
  DialogPointerDownOutsideEvent as LightboxPointerDownOutsideEvent,
  DialogTriggerValueChangeDetails as LightboxTriggerValueChangeDetails,
  UseDialogContext as UseLightboxContext,
  UseDialogProps as UseLightboxProps,
  UseDialogReturn as UseLightboxReturn,
} from '@ark-ui/react/dialog';

@layer ui.components {
  .trigger {
    cursor: zoom-in;
  }

  .backdrop {
    position: fixed;
    z-index: calc(var(--z-backdrop) + var(--layer-index, 0));
    inset: 0;
    min-height: 100dvh;
    background-color: var(--lightbox-backdrop-bg, var(--backdrop-bg, var(--color-overlay)));
    backdrop-filter: var(--backdrop-filter, blur(var(--lightbox-backdrop-blur, 4px)));

    &[data-state='open'] {
      animation: lightbox-backdrop-in var(--lightbox-backdrop-transition, var(--transition-default));
    }

    &[data-state='closed'] {
      animation: lightbox-backdrop-out
        var(--lightbox-backdrop-transition, var(--transition-default));
    }
  }

  .positioner {
    box-sizing: border-box;
    position: fixed;
    z-index: calc(var(--z-modal) + var(--layer-index, 0));
    inset: 0;
    display: grid;
    place-items: center;
    overflow: hidden;
    overscroll-behavior: contain;
    padding: var(--lightbox-positioner-padding, var(--spacing-4));
  }

  .content {
    box-sizing: border-box;
    position: relative;
    width: fit-content;
    max-width: min(var(--lightbox-content-max-width, 80vw), calc(100vw - var(--spacing-8)));
    max-height: min(var(--lightbox-content-max-height, 80dvh), calc(100dvh - var(--spacing-8)));
    border: 0;
    background: transparent;
    outline: 0;

    &[data-state='open'] {
      animation: lightbox-content-in var(--lightbox-transition, 220ms ease);
    }

    &[data-state='closed'] {
      animation: lightbox-content-out var(--lightbox-transition, 220ms ease);
    }
  }

  .image {
    display: block;
    max-width: min(var(--lightbox-media-max-width, 80vw), 100%);
    max-height: min(var(--lightbox-media-max-height, 80dvh), 100%);
    object-fit: contain;
    border-radius: var(--lightbox-media-radius, var(--radius-md));
    box-shadow: var(--lightbox-media-shadow, var(--shadow-lg));
    user-select: none;

    &[data-close-on-click] {
      cursor: zoom-out;
    }
  }

  .gallery {
    --carousel-gap: var(--lightbox-gallery-gap, var(--spacing-4));
    width: min(
      var(--lightbox-gallery-max-width, 72rem),
      calc(100vw - var(--lightbox-positioner-padding, var(--spacing-4)) * 2)
    );
    max-width: 100%;

    [data-slot='carousel-control'] {
      align-items: center;
    }

    [data-slot='carousel-item-group'] {
      aspect-ratio: var(--lightbox-gallery-aspect-ratio, 16 / 10);
      max-height: min(
        var(--lightbox-gallery-track-max-height, 68dvh),
        var(--lightbox-media-max-height, 80dvh)
      );
      background: var(
        --lightbox-gallery-track-bg,
        color-mix(in oklab, black 88%, var(--color-background) 12%)
      );
    }

    [data-slot='carousel-item'] {
      display: grid;
      height: 100%;
      place-items: center;

      img,
      video {
        display: block;
        width: 100%;
        height: 100%;
        object-fit: contain;
        border-radius: var(--lightbox-media-radius, var(--radius-md));
        user-select: none;
      }
    }

    [data-slot='carousel-indicator-group'] {
      width: fit-content;
      max-width: 100%;
      margin-inline: auto;
      flex-wrap: wrap;
    }

    [data-slot='carousel-indicator']:has(img) {
      overflow: hidden;
      width: var(--lightbox-gallery-thumbnail-width, 5rem);
      height: var(--lightbox-gallery-thumbnail-height, 3rem);
      border: var(--border-width-sm) solid transparent;
      border-radius: var(--lightbox-gallery-thumbnail-radius, var(--radius-md));
      background: transparent;
      opacity: var(--lightbox-gallery-thumbnail-opacity, 0.65);
      transition:
        border-color var(--transition-fast),
        opacity var(--transition-fast),
        transform var(--transition-fast);

      &:hover {
        opacity: var(--lightbox-gallery-thumbnail-opacity-hover, 0.9);
      }

      &[data-current] {
        width: var(--lightbox-gallery-thumbnail-width, 5rem);
        border-color: var(--lightbox-gallery-thumbnail-border-color, var(--color-primary));
        background: transparent;
        opacity: 1;
        transform: translateY(-1px);
      }

      img {
        display: block;
        width: 100%;
        height: 100%;
        object-fit: cover;
      }
    }
  }

  .closeIcon {
    --close-button-size: var(--lightbox-close-icon-size, 2rem);
    --close-button-radius: var(--lightbox-close-icon-radius, var(--radius-sm));
    --close-button-icon-size: var(--lightbox-close-icon-glyph-size, 0.875rem);
    --close-button-color: var(--lightbox-close-icon-color, var(--color-foreground));
    --close-button-color-hover: var(--lightbox-close-icon-color-hover, var(--color-foreground));
    --close-button-bg: var(--lightbox-close-icon-bg, var(--color-background));
    --close-button-bg-hover: var(--lightbox-close-icon-bg-hover, var(--color-muted));
    --close-button-focus-ring-color: var(--lightbox-close-icon-focus-ring-color, var(--color-ring));
    position: fixed;
    z-index: calc(var(--z-modal) + var(--layer-index, 0) + 1);
    inset-block-start: var(--lightbox-close-icon-inset-block-start, var(--spacing-4));
    inset-inline-end: var(--lightbox-close-icon-inset-inline-end, var(--spacing-4));
    border: 0;
    padding: 0;
    opacity: 0;
    pointer-events: none;
    visibility: hidden;

    &[data-state='open'] {
      opacity: 1;
      pointer-events: auto;
      visibility: visible;
    }
  }

  @keyframes lightbox-backdrop-in {
    from {
      opacity: var(--lightbox-backdrop-starting-opacity, 0);
      backdrop-filter: var(--lightbox-backdrop-starting-blur, none);
    }
  }

  @keyframes lightbox-backdrop-out {
    to {
      opacity: var(--lightbox-backdrop-ending-opacity, 0);
      backdrop-filter: var(--lightbox-backdrop-ending-blur, none);
    }
  }

  @keyframes lightbox-content-in {
    from {
      opacity: var(--lightbox-content-starting-opacity, 0);
      translate: var(--lightbox-content-starting-translate-x, 0)
        var(--lightbox-content-starting-translate-y, 0);
      scale: var(--lightbox-content-starting-scale, 0.82);
    }
  }

  @keyframes lightbox-content-out {
    to {
      opacity: var(--lightbox-content-ending-opacity, 0);
      translate: var(--lightbox-content-ending-translate-x, 0)
        var(--lightbox-content-ending-translate-y, 0);
      scale: var(--lightbox-content-ending-scale, 0.82);
    }
  }
}

export {
  Lightbox,
  LightboxBind,
  LightboxGallery,
  LightboxImage,
  useLightbox,
  useLightboxContext,
} from './Lightbox';
export type {
  LightboxBindProps,
  LightboxFocusOutsideEvent,
  LightboxImageSelectDetails,
  LightboxInteractOutsideEvent,
  LightboxOpenChangeDetails,
  LightboxPointerDownOutsideEvent,
  LightboxTriggerValueChangeDetails,
  UseLightboxContext,
  UseLightboxProps,
  UseLightboxReturn,
} from './Lightbox';
